from __future__ import annotations

import math
from typing import Callable, Dict, List, Optional, Tuple

import numpy as np
from scipy.optimize import least_squares
from scipy import stats as sp_stats

from .models import EquationFit, FitStats


def _model_fn(x: np.ndarray, family: str) -> Callable[[np.ndarray, Tuple[float, ...]], np.ndarray]:
    """Return a callable model_fn(params, x) -> y_pred for each canonical family."""
    if family == "linear":
        return lambda params, x: params[0] * x + params[1]
    elif family == "power":
        return lambda params, x: params[0] * np.power(np.maximum(x, 1e-10), params[1])
    elif family == "exponential":
        return lambda params, x: params[0] * np.exp(params[1] * x)
    elif family == "logarithmic":
        return lambda params, x: params[0] * np.log(np.maximum(x, 1e-10)) + params[1]
    elif family == "logistic":
        return lambda params, x: params[0] / (1.0 + np.exp(-params[1] * (x - params[2])))
    elif family == "polynomial":
        return lambda params, x: params[0] + params[1] * x + params[2] * x * x
    elif family in ("pysr_unavailable", "pysr"):
        return lambda params, x: params[0] * x
    else:
        raise ValueError(f"Unknown family: {family}")


def _initial_guess(x: np.ndarray, y: np.ndarray, family: str) -> List[float]:
    """Compute sensible initial parameters for each family."""
    if family == "linear":
        slope, intercept = np.polyfit(x, y, 1)
        return [float(slope), float(intercept)]
    elif family == "power":
        pos_mask = (x > 0) & (y > 0)
        xp = x[pos_mask] if pos_mask.any() else x + 1e-10
        yp = y[pos_mask] if pos_mask.any() else y + 1e-10
        slope, intercept = np.polyfit(np.log(xp), np.log(yp), 1)
        return [float(np.exp(intercept)), float(slope)]
    elif family == "exponential":
        pos_mask = y > 0
        xp = x[pos_mask] if pos_mask.any() else x
        yp = y[pos_mask] if pos_mask.any() else y + 1e-10
        slope, intercept = np.polyfit(xp, np.log(yp), 1)
        return [float(np.exp(intercept)), float(slope)]
    elif family == "logarithmic":
        slope, intercept = np.polyfit(np.log(np.maximum(x, 1e-10)), y, 1)
        return [float(slope), float(intercept)]
    elif family == "logistic":
        return [float(np.max(y)), 1.0, float(np.median(x))]
    elif family == "polynomial":
        coeffs = np.polyfit(x, y, 2)
        return [float(coeffs[0]), float(coeffs[1]), float(coeffs[2])]
    else:
        return [1.0, 0.0]


def _param_names(family: str) -> List[str]:
    if family == "linear":
        return ["a", "b"]
    elif family in ("power", "exponential", "logarithmic"):
        return ["a", "b"]
    elif family == "logistic":
        return ["L", "k", "x0"]
    elif family == "polynomial":
        return ["a", "b", "c"]
    return []


def _expr_string(family: str) -> str:
    if family == "linear":
        return "y = a*x + b"
    elif family == "power":
        return "y = a*x**b"
    elif family == "exponential":
        return "y = a*exp(b*x)"
    elif family == "logarithmic":
        return "y = a*ln(x) + b"
    elif family == "logistic":
        return "y = L / (1 + exp(-k*(x - x0)))"
    elif family == "polynomial":
        return "y = a + b*x + c*x**2"
    return ""


CANONICAL_FAMILIES = ["linear", "power", "exponential", "logarithmic", "logistic", "polynomial"]


def split_holdout(
    x: List[float], y: List[float], ratio: float = 0.2, temporal: bool = False
) -> Tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray]:
    x_arr = np.array(x, dtype=np.float64)
    y_arr = np.array(y, dtype=np.float64)
    n = len(x_arr)
    split_idx = int(n * (1 - ratio))
    if temporal:
        return x_arr[:split_idx], x_arr[split_idx:], y_arr[:split_idx], y_arr[split_idx:]
    indices = np.random.RandomState(42).permutation(n)
    train_idx = indices[:split_idx]
    holdout_idx = indices[split_idx:]
    return x_arr[train_idx], x_arr[holdout_idx], y_arr[train_idx], y_arr[holdout_idx]


def _compute_r2(y_true: np.ndarray, y_pred: np.ndarray, n_params: int) -> Tuple[float, float]:
    ss_res = np.sum((y_true - y_pred) ** 2)
    ss_tot = np.sum((y_true - np.mean(y_true)) ** 2)
    r2 = 1.0 - ss_res / ss_tot if ss_tot > 0 else 0.0
    n = len(y_true)
    r2_adj = 1.0 - (1.0 - r2) * (n - 1) / max(n - n_params - 1, 1)
    return float(r2), float(r2_adj)


def _compute_aic(n: int, n_params: int, rss: float) -> float:
    if n <= n_params + 1:
        return float("inf")
    if rss <= 0:
        rss = 1e-300
    aic = n * math.log(rss / n) + 2 * n_params
    return float(aic)


def _compute_holdout_mape(model_fn: Callable, params: Tuple[float, ...], x_hold: np.ndarray, y_hold: np.ndarray) -> float:
    if len(x_hold) == 0:
        return float("inf")
    y_pred = model_fn(params, x_hold)
    mask = np.abs(y_hold) > 1e-10
    if not mask.any():
        return float("inf")
    mape = np.mean(np.abs((y_hold[mask] - y_pred[mask]) / y_hold[mask])) * 100
    return float(mape)


def _durbin_watson(residuals: np.ndarray) -> float:
    diff = np.diff(residuals)
    numerator = np.sum(diff * diff)
    denominator = np.sum(residuals * residuals)
    return float(numerator / denominator) if denominator > 0 else 2.0


def _residuals_random(residuals: np.ndarray, threshold: float = 0.05) -> bool:
    if len(residuals) < 10:
        return True
    dw = _durbin_watson(residuals)
    stat, p_value = sp_stats.shapiro(residuals)
    return bool(1.5 < dw < 2.5 and p_value > threshold)


def compute_fit_stats(
    model_fn: Callable,
    params: Tuple[float, ...],
    x: np.ndarray,
    y: np.ndarray,
    x_hold: np.ndarray,
    y_hold: np.ndarray,
    n_params: int,
) -> FitStats:
    y_pred = model_fn(params, x)
    residuals = y - y_pred
    rss = float(np.sum(residuals**2))
    r2, r2_adj = _compute_r2(y, y_pred, n_params)
    aic = _compute_aic(len(x), n_params, rss)
    holdout_mape = _compute_holdout_mape(model_fn, params, x_hold, y_hold)
    resid_ok = _residuals_random(residuals)
    return FitStats(
        r2_adj=r2_adj,
        holdout_mape=holdout_mape,
        aic=aic,
        residual_random=resid_ok,
        n_obs=len(x),
    )


def fit_canonical_families(
    x: List[float], y: List[float], temporal: bool = False
) -> List[EquationFit]:
    x_train, x_hold, y_train, y_hold = split_holdout(x, y, ratio=0.2, temporal=temporal)

    results: List[EquationFit] = []
    for family in CANONICAL_FAMILIES:
        try:
            init = _initial_guess(x_train, y_train, family)
            fn = _model_fn(x_train, family)

            def residual(params: np.ndarray) -> np.ndarray:
                return fn(tuple(params), x_train) - y_train

            result = least_squares(residual, np.array(init), method="trf", loss="soft_l1", max_nfev=2000)

            if not result.success:
                continue

            params = tuple(result.x)
            n_params = len(params)
            stats = compute_fit_stats(fn, params, x_train, y_train, x_hold, y_hold, n_params)
            param_dict = dict(zip(_param_names(family), params))
            expr = _expr_string(family)
            results.append(EquationFit(family=family, parameters=param_dict, stats=stats, sympy_expr=expr))
        except Exception:
            continue

    return results


def structural_validity(params: Dict[str, float], family: str, domain: str) -> bool:
    if family == "power":
        a = params.get("a", 0)
        b = params.get("b", 0)
        if domain.startswith("finance") and b > 0:
            return False
        if a < 0:
            return False
    elif family == "exponential":
        b = params.get("b", 0)
        if domain.startswith("finance.saas") and b > 0:
            return False
    elif family == "logistic":
        L_val = params.get("L", 0)
        if L_val < 0:
            return False
    return True


def choose_best(candidates: List[EquationFit]) -> Optional[EquationFit]:
    valid = [c for c in candidates if not math.isinf(c.stats.aic)]
    if not valid:
        return None
    return min(valid, key=lambda c: c.stats.aic)

