        return [float(np.exp(intercept)), float(slope)]
    elif family == "exponential":
        pos_mask = y > 0
        xp = x[pos_mask] if pos_mask.any() else x
        yp = y[pos_mask] if pos_mask.any() else y + 1e-10
        slope, intercept = np.polyfit(xp, np.log(yp), 1)
        return [float(np.exp(intercept)), float(slope)]
    elif family == "logarithmic":
