def test_el_prediction_directionally_correct_at_extreme(self, client):
    """At tenure=60mo, EL must predict lower churn than at tenure=6mo.
    Uses aggregated bucketed churn rates so the signal isn't drowned
    by individual-level binary noise on 7k rows."""
    # Aggregate into tenure buckets for clean signal
    buckets = defaultdict(list)
    for t, c in zip(_TENURE, _CHURN_BINARY):
        buckets[int(t) // 12 * 12].append(c)
    bucketed_tenure = []
    bucketed_churn = []
    for t in sorted(buckets):
        bucketed_tenure.append(float(t + 6))  # bucket midpoint
        bucketed_churn.append(sum(buckets[t]) / len(buckets[t]))
    r_low = client.post("/v1/solve", json={
        "query": "Churn at low tenure",
        "x_values": bucketed_tenure, "y_values": bucketed_churn, "x_value": 6,
    })
    r_high = client.post("/v1/solve", json={
        "query": "Churn at high tenure",
        "x_values": bucketed_tenure, "y_values": bucketed_churn, "x_value": 60,
    })
    assert r_low.status_code == 200 and r_high.status_code == 200
    assert r_high.json()["answer"] < r_low.json()["answer"], (
        "EL predicts churn at 60mo >= churn at 6mo. "
        "Ground truth: 48% (0-11mo) vs 8% (60-71mo)."
    )

